rows.customCode:
(() => {
  if (window.__pcbw_foundry_mentor_init) return;
  window.__pcbw_foundry_mentor_init = true;

  oc.thread.customData ??= {};
  oc.character.customData ??= {};
  oc.character.customData.PUBLIC ??= {};

  const STATE_KEY = "__pcbw_foundry_mentor_state";
  const INJECT_KEY = "__pcbw_foundry_mentor_injection";
  const UI_KEY = "__pcbw_foundry_mentor_ui";

  const LEVELS = ["beginner", "intermediate", "advanced", "expert"];
  const TAB_LABELS = {
    learn: "Learn",
    fieldmap: "Field Map",
    codelab: "Code Lab",
    challenge: "Challenge",
    minibuild: "Mini Build",
    progress: "Progress",
    help: "Help",
    reset: "Reset"
  };

  const LESSONS = {
    roleInstruction: {
      title: "roleInstruction",
      explainer: "Defines the bot's core behavior contract. It sets role, scope, constraints, and mission.",
      code: "// roleInstruction\nYou are a Perchance bot mentor that teaches creator fields and customCode patterns.",
      pitfall: "Treating roleInstruction like runtime state. It is prompting baseline, not a state store.",
      nextStep: "Pair it with reminderMessage so responses stay aligned as threads grow."
    },
    reminderMessage: {
      title: "reminderMessage",
      explainer: "Single reinforcement string appended before each AI reply.",
      code: "oc.character.reminderMessage = \"Use real field names and keep examples short.\";",
      pitfall: "Appending endlessly creates reminder garbage. Rebuild full reminder each update.",
      nextStep: "Route reminder text by level and active tab."
    },
    generalWritingInstructions: {
      title: "generalWritingInstructions",
      explainer: "Response style guidance layered with roleInstruction.",
      code: "generalWritingInstructions: \"Use concise structured teaching.\"",
      pitfall: "Using it for hard runtime logic. Put runtime logic in customCode.",
      nextStep: "Use maxParagraphCountPerMessage to keep output compact."
    },
    initialMessages: {
      title: "initialMessages",
      explainer: "Seeds each new thread with message objects.",
      code: "initialMessages: [{ author: \"system\", content: \"Setup\", hiddenFrom: [\"ai\"] }]",
      pitfall: "Using plain transcript text instead of valid message objects.",
      nextStep: "Use hiddenFrom and expectsReply intentionally."
    },
    hiddenFrom: {
      title: "hiddenFrom",
      explainer: "Per-message visibility control.",
      code: "{ author: \"system\", content: \"AI-only context\", hiddenFrom: [\"user\"] }",
      pitfall: "Using a string like \"ai\" instead of array [\"ai\"].",
      nextStep: "Use hidden system injections for current mentor state only."
    },
    expectsReply: {
      title: "expectsReply",
      explainer: "Controls whether a message should trigger an AI reply.",
      code: "{ author: \"system\", content: \"Status updated\", expectsReply: false }",
      pitfall: "Using 0/1 instead of true/false.",
      nextStep: "Use false for UI feedback and command confirmations."
    },
    messageWrapperStyle: {
      title: "messageWrapperStyle",
      explainer: "CSS string applied to rendered messages.",
      code: "messageWrapperStyle: \"border-left:4px solid #6eb4ff;\"",
      pitfall: "Expecting wrapper style to change panel UI. It styles messages only.",
      nextStep: "Keep styles compact and mobile-safe."
    },
    imagePromptFields: {
      title: "imagePromptPrefix / Suffix / Triggers",
      explainer: "Image prompt shaping fields for generation workflows.",
      code: "imagePromptPrefix: \"cinematic lighting,\"",
      pitfall: "Assuming imagePromptTriggers is an array. It is a string field.",
      nextStep: "Use customCode only when dynamic image prompt routing is needed."
    },
    threadMessages: {
      title: "oc.thread.messages",
      explainer: "Live message array for thread history and runtime manipulation.",
      code: "const last = oc.thread.messages.at(-1);",
      pitfall: "Mutating old messages blindly without scope checks.",
      nextStep: "Use targeted cleanup for stale hidden injections only."
    },
    messageAdded: {
      title: "oc.thread.on(\"MessageAdded\")",
      explainer: "Event hook for runtime behaviors on new messages.",
      code: "oc.thread.on(\"MessageAdded\", ({ message }) => { /* ... */ });",
      pitfall: "Registering duplicate listeners on rerun.",
      nextStep: "Use one init guard and one owned listener pipeline."
    },
    threadState: {
      title: "oc.thread.customData",
      explainer: "Thread-local persistent state. Best place for per-conversation course progress.",
      code: "oc.thread.customData.__pcbw_foundry_mentor_state = { xp: 0 };",
      pitfall: "Storing global preferences here when they should be character-scoped.",
      nextStep: "Keep progress, lesson state, and unlocks thread-local."
    },
    characterState: {
      title: "oc.character.customData",
      explainer: "Character-global state shared across threads for this character.",
      code: "oc.character.customData.PUBLIC.defaultLevel = \"beginner\";",
      pitfall: "Using this for per-thread XP and challenge progress.",
      nextStep: "Use character scope only for stable cross-thread defaults."
    },
    publicState: {
      title: "oc.character.customData.PUBLIC",
      explainer: "Safe public namespace for global preferences and metadata.",
      code: "oc.character.customData.PUBLIC.mentorPrefs = { panelPinned: true };",
      pitfall: "Treating PUBLIC as private secure storage.",
      nextStep: "Limit PUBLIC to non-sensitive global preferences."
    },
    threadShortcuts: {
      title: "oc.thread.shortcutButtons",
      explainer: "Live thread-specific shortcuts for convenience prompts.",
      code: "oc.thread.shortcutButtons = [{ name: \"Explain reminderMessage\", message: \"Explain reminderMessage at my level.\", insertionType: \"replace\", autoSend: true, clearAfterSend: true }];",
      pitfall: "Using shortcuts as the only navigation model.",
      nextStep: "Keep panel buttons as primary controls."
    },
    characterShortcuts: {
      title: "oc.character.shortcutButtons",
      explainer: "Character-level default shortcut template.",
      code: "oc.character.shortcutButtons = [];",
      pitfall: "Overwriting character defaults when only one thread needs changes.",
      nextStep: "Prefer thread shortcuts for session-specific guidance."
    },
    hiddenSystemInjection: {
      title: "Hidden system injection",
      explainer: "Inject one current-state hidden system message before useful teaching replies.",
      code: "oc.thread.messages.push({ author: \"system\", content: stateText, hiddenFrom: [\"user\"], expectsReply: false });",
      pitfall: "Letting injections stack forever.",
      nextStep: "Remove stale tagged injections before adding the latest one."
    },
    dynamicReminderRouting: {
      title: "Dynamic reminder routing",
      explainer: "Rebuild reminderMessage from level + tab + lesson context.",
      code: "oc.character.reminderMessage = buildReminder(state);",
      pitfall: "Multiple writers clobbering reminderMessage without ownership.",
      nextStep: "Centralize reminder writes in one function."
    },
    stateOwnership: {
      title: "State ownership",
      explainer: "Thread and character scopes are not interchangeable.",
      code: "// thread: progress; character: defaults",
      pitfall: "Cross-thread leakage from character-global progress values.",
      nextStep: "Audit each state key by lifecycle and owner."
    },
    iframeSafeUi: {
      title: "iframe-safe UI design",
      explainer: "Compact floating panel with touch-safe controls works reliably in Perchance iframe.",
      code: "panel.style.cssText = \"position:fixed;max-width:360px;\";",
      pitfall: "Designing like a full desktop SPA.",
      nextStep: "Use compact tabs and concise controls only."
    },
    commonFailureModes: {
      title: "Common failure modes",
      explainer: "Most failures are listener duplication, reminder ownership conflicts, stale injections, and broken button/message object contracts.",
      code: "if (window.__pcbw_foundry_mentor_init) return;",
      pitfall: "Ignoring object type constraints causes import errors.",
      nextStep: "Validate export with validator + unittest before promotion."
    }
  };

  const FIELD_MAP = {
    "Prompting / behavior": [
      ["roleInstruction", "character editor", "Core behavioral contract", "Runtime state storage", "Trying to track progress in roleInstruction"],
      ["reminderMessage", "character editor or customCode", "Reply-time reinforcement", "Historical message rewrite", "Appending layered reminders"],
      ["generalWritingInstructions", "character editor", "Output style and form", "Event wiring", "Using it as a command parser"]
    ],
    "Thread seeding": [
      ["initialMessages", "character field", "New-thread bootstrap", "Existing thread retrofit", "Invalid message object shape"],
      ["hiddenFrom", "message object", "Visibility per audience", "Permission model", "Using string instead of array"],
      ["expectsReply", "message object", "Reply trigger intent", "AI quality guarantee", "Using 0/1 instead of boolean"]
    ],
    "Visuals": [
      ["messageWrapperStyle", "character field", "Message container CSS", "Panel layout", "Overly wide non-mobile-safe CSS"],
      ["avatar / scene", "character field", "Persona visuals", "State machine logic", "Expecting avatar changes from reminderMessage"],
      ["image prompt fields", "character field", "Image prompt shaping", "General chat behavior", "Wrong type for imagePromptTriggers"]
    ],
    "Runtime logic": [
      ["customCode", "character field", "Runtime behavior and UI", "Static seed content", "Duplicate listeners due to missing init guard"],
      ["oc.thread.messages", "runtime object", "Message inspection/mutation", "Cross-thread memory", "Blindly mutating every message"],
      ["MessageAdded", "runtime event", "Reactive workflows", "One-time static setup", "Parsing fragile full CLI grammars"],
      ["messageRenderingPipeline", "runtime pipeline", "Render-time transforms", "Thread persistence", "Heavy handlers causing jank"]
    ],
    "State": [
      ["oc.thread.customData", "runtime thread scope", "Per-conversation progress", "Cross-thread defaults", "Storing global defaults here"],
      ["oc.character.customData", "runtime character scope", "Cross-thread shared preferences", "Session isolation", "Storing XP here"],
      ["oc.character.customData.PUBLIC", "runtime public scope", "Public global preferences", "Private secrets", "Saving sensitive data in PUBLIC"]
    ],
    "Controls": [
      ["shortcutButtons", "character field", "Default shortcut definitions", "Panel UI logic", "Missing required button fields"],
      ["oc.thread.shortcutButtons", "runtime thread scope", "Live convenience shortcuts", "Primary navigation", "Replacing panel-first UX with shortcuts"],
      ["optional typed aliases", "MessageAdded interceptor", "Power-user command aliases", "Main UX flow", "Making aliases mandatory"]
    ]
  };

  const CODE_LAB = {
    "tiny snippet": "// Where: customCode\\noc.thread.on(\"MessageAdded\", ({ message }) => {\\n  if (message.author !== \"user\") return;\\n  // tiny event hook\\n});",
    "beginner patch": "// Where: reminderMessage + customCode\\noc.character.reminderMessage = \"Explain one Perchance concept at a time.\";",
    "command interceptor": "// Where: MessageAdded handler\\nif (/^\\/mentor\\b/i.test(message.content)) {\\n  const idx = oc.thread.messages.indexOf(message);\\n  if (idx >= 0) oc.thread.messages.splice(idx, 1);\\n}",
    "hidden system injection": "// Where: customCode runtime\\noc.thread.messages.push({\\n  author: \"system\",\\n  content: \"Mentor state snapshot\",\\n  hiddenFrom: [\"user\"],\\n  expectsReply: false\\n});",
    "reminder router": "// Where: customCode runtime\\noc.character.reminderMessage = buildReminder(state);",
    "live shortcut orchestration": "// Where: customCode runtime\\noc.thread.shortcutButtons = [\\n  { name: \"Explain roleInstruction\", message: \"Explain roleInstruction at my level.\", insertionType: \"replace\", autoSend: true, clearAfterSend: true }\\n];",
    "state-safe init pattern": "// Where: top of customCode\\noc.thread.customData ??= {};\\noc.thread.customData.__pcbw_foundry_mentor_state ??= { xp: 0 };",
    "message rendering / button action pattern": "// Where: customCode UI + event delegation\\npanel.addEventListener(\"click\", (event) => {\\n  const btn = event.target.closest(\"button[data-action]\");\\n  if (!btn) return;\\n  // route action\\n});"
  };

  const CHALLENGES = [
    "Intercept one alias command and safely remove it before AI sees it.",
    "Inject one hidden mentor-state message and clean stale copies.",
    "Route reminder text by level and active tab.",
    "Explain why thread state is safer than character state for per-conversation progress.",
    "Add one live shortcut button while keeping valid object fields."
  ];

  const MINI_BUILDS = [
    "Mode-switching bot",
    "Relationship progression bot",
    "Tutorial bot",
    "Lore-aware helper",
    "Multi-character coordination bot",
    "UI-heavy mentor bot",
    "Hidden-system-injection bot",
    "State-safe slash-alias utility bot"
  ];

  function createDefaultState() {
    return {
      level: "",
      xp: 0,
      streak: 0,
      badges: [],
      unlockedTopics: [],
      completedLessons: [],
      currentLesson: "",
      currentChallenge: "",
      currentMiniBuild: "",
      activeMode: "selection",
      activeTab: "learn",
      lastFieldViewed: "",
      panelVisible: true,
      helpViewed: false,
      pendingReset: false,
      recentAiHashes: []
    };
  }

  function ensureState() {
    const existing = oc.thread.customData[STATE_KEY];
    const defaults = createDefaultState();
    if (!existing || typeof existing !== "object" || Array.isArray(existing)) {
      oc.thread.customData[STATE_KEY] = defaults;
      return oc.thread.customData[STATE_KEY];
    }
    for (const key of Object.keys(defaults)) {
      if (!(key in existing)) {
        existing[key] = defaults[key];
      }
    }
    if (!Array.isArray(existing.badges)) existing.badges = [];
    if (!Array.isArray(existing.unlockedTopics)) existing.unlockedTopics = [];
    if (!Array.isArray(existing.completedLessons)) existing.completedLessons = [];
    if (!Array.isArray(existing.recentAiHashes)) existing.recentAiHashes = [];
    return existing;
  }

  const state = ensureState();
  oc.character.customData.PUBLIC.mentorDefaults ??= { defaultLevel: "" };

  function escapeHtml(text) {
    return String(text)
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/\"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function compactList(items) {
    if (!items.length) return "<div class=\"pcbw-muted\">None yet.</div>";
    return "<ul>" + items.map(item => "<li>" + escapeHtml(item) + "</li>").join("") + "</ul>";
  }

  function grantXp(amount) {
    state.xp += amount;
    state.streak += 1;
    if (state.xp >= 40 && !state.badges.includes("Field Mapper")) state.badges.push("Field Mapper");
    if (state.xp >= 80 && !state.badges.includes("Snippet Smith")) state.badges.push("Snippet Smith");
    if (state.xp >= 140 && !state.badges.includes("Foundry Architect")) state.badges.push("Foundry Architect");
    if (state.xp >= 220 && !state.badges.includes("Runtime Steward")) state.badges.push("Runtime Steward");
  }

  function ensureUnlocked(topic) {
    if (!topic) return;
    if (!state.unlockedTopics.includes(topic)) state.unlockedTopics.push(topic);
  }

  function buildReminder() {
    const level = state.level || "beginner";
    const tab = state.activeTab || "learn";
    const lesson = state.currentLesson || "";
    const levelModes = {
      beginner: "Beginner mode: plain language, tiny examples, one concept at a time.",
      intermediate: "Intermediate mode: guided implementation and field interaction.",
      advanced: "Advanced mode: architecture, lifecycle, and tradeoffs.",
      expert: "Expert mode: precise runtime/export reasoning with concise technical detail."
    };
    return [
      "Teach Perchance/OpenCharacters specifically. Match the selected level. Prefer panel-first workflow, real field names, real oc objects, and realistic iframe constraints. Explain what code changes, where it lives, one pitfall, and the next step. Do not drift into generic JavaScript teaching without tying it back to Perchance.",
      levelModes[level],
      "Active tab: " + tab + ".",
      lesson ? "Current lesson focus: " + lesson + "." : "Current lesson focus: choose a topic from Learn.",
      "Reminder routing owner: this mentor runtime. Rebuild reminder fully per update."
    ].join(" ");
  }

  function removeStaleMentorInjections() {
    for (let i = oc.thread.messages.length - 1; i >= 0; i -= 1) {
      const msg = oc.thread.messages[i];
      if (!msg || msg.author !== "system") continue;
      if (msg.customData && msg.customData[INJECT_KEY]) {
        oc.thread.messages.splice(i, 1);
      }
    }
  }

  function injectMentorStateMessage() {
    const posture = state.level
      ? state.level === "beginner"
        ? "gentle and stepwise"
        : state.level === "intermediate"
          ? "guided and practical"
          : state.level === "advanced"
            ? "architectural with tradeoffs"
            : "precise and dense"
      : "awaiting level selection";

    removeStaleMentorInjections();

    oc.thread.messages.push({
      author: "system",
      content: [
        "Mentor runtime state:",
        "- level: " + (state.level || "unset"),
        "- activeTab: " + state.activeTab,
        "- currentLesson: " + (state.currentLesson || "none"),
        "- currentChallenge: " + (state.currentChallenge || "none"),
        "- unlockedTopics: " + (state.unlockedTopics.length ? state.unlockedTopics.join(", ") : "none"),
        "- teachingPosture: " + posture,
        "- constraints: panel-first UX, Perchance-specific instruction, realistic iframe behavior"
      ].join("\n"),
      hiddenFrom: ["user"],
      expectsReply: false,
      customData: {
        [INJECT_KEY]: true,
        createdAt: Date.now()
      }
    });
  }

  function refreshLiveShortcuts() {
    if (!state.level) {
      oc.thread.shortcutButtons = [];
      return;
    }
    oc.thread.shortcutButtons = [
      {
        name: "Explain roleInstruction",
        message: "Explain roleInstruction at my current level.",
        insertionType: "replace",
        autoSend: true,
        clearAfterSend: true
      },
      {
        name: "Tiny reminder example",
        message: "Show me a tiny reminderMessage example.",
        insertionType: "replace",
        autoSend: true,
        clearAfterSend: true
      },
      {
        name: "Thread vs character state",
        message: "Compare thread state and character state for this bot.",
        insertionType: "replace",
        autoSend: true,
        clearAfterSend: true
      },
      {
        name: "Debug drill",
        message: "Give me a small debugging challenge about MessageAdded handlers.",
        insertionType: "replace",
        autoSend: true,
        clearAfterSend: true
      },
      {
        name: "Interceptor snippet",
        message: "Show me a MessageAdded interception snippet with safe command removal.",
        insertionType: "replace",
        autoSend: true,
        clearAfterSend: true
      }
    ];
  }

  const style = document.createElement("style");
  style.id = "pcbw-foundry-mentor-style";
  style.textContent = `
    #pcbw-foundry-mentor-panel {
      position: fixed;
      right: 10px;
      bottom: 10px;
      width: min(360px, calc(100vw - 20px));
      max-height: min(76vh, 620px);
      z-index: 10090;
      display: flex;
      flex-direction: column;
      border-radius: 12px;
      border: 1px solid rgba(122, 150, 220, 0.35);
      background: linear-gradient(180deg, rgba(16, 18, 28, 0.98), rgba(10, 12, 20, 0.98));
      box-shadow: 0 14px 38px rgba(0, 0, 0, 0.44);
      color: #e8edff;
      overflow: hidden;
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, sans-serif;
    }
    #pcbw-foundry-mentor-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 8px 10px;
      border-bottom: 1px solid rgba(120, 145, 210, 0.28);
      background: rgba(20, 26, 40, 0.9);
      gap: 8px;
    }
    #pcbw-foundry-mentor-header strong {
      font-size: 12px;
      letter-spacing: .3px;
      text-transform: uppercase;
      color: #bcd0ff;
    }
    .pcbw-mentor-meta {
      font-size: 11px;
      color: #9cb3ef;
    }
    .pcbw-mentor-btn {
      border: 1px solid rgba(124, 157, 236, 0.35);
      background: rgba(30, 42, 66, 0.92);
