  document.head.appendChild(style);

  const toastWrap = document.createElement("div");
  toastWrap.className = "pcbw-toast-wrap";
  document.body.appendChild(toastWrap);

  function showToast(message) {
    const toast = document.createElement("div");
    toast.className = "pcbw-toast";
    toast.textContent = message;
    toastWrap.appendChild(toast);
    requestAnimationFrame(() => toast.classList.add("show"));

    while (toastWrap.children.length > 3) {
      toastWrap.removeChild(toastWrap.firstChild);
    }

    setTimeout(() => {
      toast.classList.remove("show");
      setTimeout(() => {
        if (toast.parentNode) toast.parentNode.removeChild(toast);
      }, 200);
    }, 2200);
  }

  const panel = document.createElement("section");
  panel.id = "pcbw-foundry-mentor-panel";

  const opener = document.createElement("button");
  opener.id = "pcbw-foundry-mentor-open";
