    if (state.activeTab === "learn") return renderLearnTab();
    if (state.activeTab === "fieldmap") return renderFieldMapTab();
    if (state.activeTab === "codelab") return renderCodeLabTab();
    if (state.activeTab === "challenge") return renderChallengeTab();
    if (state.activeTab === "minibuild") return renderMiniBuildTab();
    if (state.activeTab === "progress") return renderProgressTab();
    if (state.activeTab === "help") return renderHelpTab();
    if (state.activeTab === "reset") return renderResetTab();
    return renderLearnTab();
  }

