    const tabs = Object.entries(TAB_LABELS)
      .map(([tab, label]) => {
        const active = state.activeTab === tab ? " active" : "";
        return "<button class=\"pcbw-tab-btn" + active + "\" data-action=\"tab\" data-tab=\"" + tab + "\">" + label + "</button>";
      })
      .join("");

    panel.innerHTML = [
      "<div id=\"pcbw-foundry-mentor-header\">",
      "<div>",
      "<strong>Perchance Foundry Mentor</strong>",
      "<div class=\"pcbw-mentor-meta\">",
      "Level: " + escapeHtml(state.level || "unset") + " · XP: " + String(state.xp),
      "</div>",
      "</div>",
      "<div class=\"pcbw-grid-2\" style=\"min-width:120px;\">",
      "<button class=\"pcbw-mentor-btn ghost\" data-action=\"toggle-panel\">Hide</button>",
      "<button class=\"pcbw-mentor-btn ghost\" data-action=\"tab\" data-tab=\"help\">Help</button>",
      "</div>",
      "</div>",
      (state.level && state.activeMode !== "selection") ? "<div id=\"pcbw-foundry-mentor-tabs\">" + tabs + "</div>" : "",
