    const lesson = LESSONS[topic];
    if (!lesson) return;
    systemFeedback(
      "Mentor panel lesson selected: " + lesson.title + "\n" +
      "Explain for level " + (state.level || "beginner") + ". " +
      "Format: what it is, where it lives, what it changes, one pitfall, next step."
    );
