  function drillPrompt(topic) {
    const lesson = LESSONS[topic];
    if (!lesson) return;
    systemFeedback(
      "Create one practical drill for lesson \"" + lesson.title + "\" at level " + (state.level || "beginner") +
      ". Include acceptance criteria and one common bug check."
