  function debugReviewPrompt() {
    if (!state.currentChallenge) {
      showToast("Select a challenge first.");
      return;
    }
    systemFeedback(
      "Run a debug review for this challenge: " + state.currentChallenge +
      ". Explain likely failure mode, minimal patch strategy, and validation checks."
