  panel.addEventListener("click", event => {
    const button = event.target.closest("button[data-action]");
    if (!button) return;

    const action = button.dataset.action;

    if (action === "toggle-panel") {
      state.panelVisible = false;
      renderPanel();
      return;
    }

    if (action === "reopen-panel") {
      state.panelVisible = true;
      renderPanel();
      return;
    }

    if (action === "set-level") {
      const level = (button.dataset.level || "").toLowerCase();
      if (!LEVELS.includes(level)) return;
      state.level = level;
      state.activeMode = "mentor";
      state.activeTab = "learn";
      state.pendingReset = false;
      oc.character.customData.PUBLIC.mentorDefaults.defaultLevel = level;
      refreshLiveShortcuts();
      ensureUnlocked("roleInstruction");
      ensureUnlocked("reminderMessage");
      showToast("Level set: " + level);
      renderPanel();
      return;
    }

    if (action === "tab") {
      state.activeTab = button.dataset.tab || "learn";
      if (state.activeTab === "help") state.helpViewed = true;
      state.activeMode = state.level ? "mentor" : "selection";
      renderPanel();
      return;
    }

    if (action === "lesson") {
      const topic = button.dataset.topic;
      if (!LESSONS[topic]) return;
      state.currentLesson = topic;
      state.lastFieldViewed = topic;
      ensureUnlocked(topic);
      showToast("Lesson: " + LESSONS[topic].title);
      renderPanel();
      lessonPrompt(topic);
      return;
    }

    if (action === "complete-lesson") {
      const topic = button.dataset.topic;
      if (!topic) return;
      if (!state.completedLessons.includes(topic)) {
        state.completedLessons.push(topic);
        grantXp(10);
      }
      ensureUnlocked(topic);
      showToast("Lesson completed +10 XP");
      renderPanel();
      return;
    }

    if (action === "drill") {
      const topic = button.dataset.topic;
      drillPrompt(topic);
      showToast("Drill prompt added");
      return;
    }

    if (action === "ask-codelab") {
      const category = button.dataset.category || "tiny snippet";
      codeLabPrompt(category);
      showToast("Code lab prompt added");
      return;
    }

    if (action === "set-challenge") {
      state.currentChallenge = button.dataset.value || "";
      ensureUnlocked("commonFailureModes");
      showToast("Challenge selected");
      renderPanel();
      return;
    }

    if (action === "complete-challenge") {
      if (!state.currentChallenge) {
        showToast("Choose a challenge first.");
        return;
      }
      grantXp(15);
      showToast("Challenge completed +15 XP");
      renderPanel();
      return;
    }

    if (action === "request-review") {
      debugReviewPrompt();
      showToast("Debug review prompt added");
      return;
    }

    if (action === "set-minibuild") {
      state.currentMiniBuild = button.dataset.value || "";
      ensureUnlocked("stateOwnership");
      showToast("Mini build selected");
      renderPanel();
      return;
    }

    if (action === "complete-minibuild") {
      if (!state.currentMiniBuild) {
        showToast("Choose a mini build first.");
        return;
      }
      grantXp(20);
      showToast("Mini build completed +20 XP");
      renderPanel();
      return;
    }

    if (action === "plan-minibuild") {
      miniBuildPlanPrompt();
      showToast("Mini-build planning prompt added");
      return;
    }

    if (action === "show-aliases") {
      systemFeedback(
        "Optional aliases: /mentor, /mentor help, /mentor progress, /mentor lesson roleInstruction, /mentor lesson reminderMessage, /mentor lesson initialMessages, /mentor lesson shortcutButtons, /mentor lesson customCode, /mentor lesson MessageAdded, /mentor reset"
      );
      showToast("Optional aliases posted");
      return;
    }

    if (action === "request-reset") {
      state.pendingReset = true;
      state.activeTab = "reset";
      renderPanel();
      return;
    }

    if (action === "cancel-reset") {
      state.pendingReset = false;
      renderPanel();
      return;
    }

    if (action === "confirm-reset") {
      const fresh = createDefaultState();
      oc.thread.customData[STATE_KEY] = fresh;
      Object.assign(state, fresh);
      state.activeMode = "selection";
      state.activeTab = "learn";
      oc.thread.shortcutButtons = [];
      showToast("Mentor state reset");
      renderPanel();
      return;
    }
  });

  opener.addEventListener("click", () => {
    state.panelVisible = true;
    renderPanel();
  });

  function normalizeTopic(raw) {
    const normalized = (raw || "").trim();
    const direct = Object.keys(LESSONS).find(key => key.toLowerCase() === normalized.toLowerCase());
    if (direct) return direct;
    if (/messageadded/i.test(normalized)) return "messageAdded";
    if (/shortcutbuttons/i.test(normalized)) return "threadShortcuts";
    if (/customcode/i.test(normalized)) return "commonFailureModes";
    return "";
  }

  function handleMentorAlias(message) {
    const text = (message.content || "").trim();
    if (!/^\/mentor\b/i.test(text)) return false;

    const parts = text.split(/\s+/).slice(1);
    const sub = (parts[0] || "").toLowerCase();

    const idx = oc.thread.messages.indexOf(message);
    if (idx >= 0) oc.thread.messages.splice(idx, 1);

    state.panelVisible = true;

    if (!sub) {
      renderPanel();
      showToast("Mentor panel opened");
      return true;
    }

    if (sub === "help") {
      state.activeTab = "help";
      state.helpViewed = true;
      renderPanel();
      showToast("Help tab opened");
      return true;
    }

    if (sub === "progress") {
      state.activeTab = "progress";
      renderPanel();
      showToast("Progress tab opened");
      return true;
    }

    if (sub === "reset") {
      state.activeTab = "reset";
      state.pendingReset = true;
      renderPanel();
      showToast("Reset confirmation opened");
      return true;
    }

    if (sub === "lesson") {
      const topicText = parts.slice(1).join(" ");
      const topic = normalizeTopic(topicText);
      if (topic && LESSONS[topic]) {
        state.currentLesson = topic;
        state.activeTab = "learn";
        ensureUnlocked(topic);
        renderPanel();
        lessonPrompt(topic);
        showToast("Lesson selected from alias");
      } else {
        systemFeedback("Unknown lesson alias topic. Use Field Map or Learn tab to pick a valid lesson.");
        showToast("Unknown lesson topic");
      }
      return true;
    }

    systemFeedback("Unknown /mentor alias. Use: /mentor, /mentor help, /mentor progress, /mentor lesson <topic>, /mentor reset");
    showToast("Unknown alias command");
    return true;
  }

  function simpleHash(str) {
    let hash = 0;
    const s = String(str || "").slice(0, 800);
    for (let i = 0; i < s.length; i += 1) {
      hash = ((hash << 5) - hash) + s.charCodeAt(i);
      hash |= 0;
    }
    return hash;
  }

  function sanitizeAiMessageContent(content) {
    const parser = new DOMParser();
    const doc = parser.parseFromString("<div>" + String(content || "") + "</div>", "text/html");
    const root = doc.body.firstChild;
    const banned = ["script", "iframe", "object", "embed", "form", "style"];

    banned.forEach(tag => {
      let nodes = root.getElementsByTagName(tag);
      while (nodes.length > 0) {
        nodes[0].remove();
        nodes = root.getElementsByTagName(tag);
      }
    });

    const all = root.querySelectorAll("*");
    all.forEach(node => {
      for (const attr of [...node.attributes]) {
        const name = attr.name.toLowerCase();
        const value = String(attr.value || "");
        if (name.startsWith("on")) node.removeAttribute(attr.name);
        if ((name === "href" || name === "src") && /^\s*javascript:/i.test(value)) {
          node.removeAttribute(attr.name);
        }
      }
    });

    return root.innerHTML;
  }

  let handlingEvent = false;

  oc.thread.on("MessageAdded", ({ message }) => {
    if (handlingEvent) return;
    handlingEvent = true;

    try {
      if (!message || !message.author) {
        handlingEvent = false;
        return;
      }

      if (message.author === "user") {
        if (handleMentorAlias(message)) {
          oc.character.reminderMessage = buildReminder();
          handlingEvent = false;
          return;
        }

        if (state.level) {
          injectMentorStateMessage();
        }

        oc.character.reminderMessage = buildReminder();
      }

      if (message.author === "ai") {
        const current = message.content || "";
        const sanitized = sanitizeAiMessageContent(current);
        if (sanitized !== current) {
          message.content = sanitized;
        }

        const hash = simpleHash(message.content || "");
        const duplicate = state.recentAiHashes.includes(hash);
        if (duplicate) {
          const idx = oc.thread.messages.indexOf(message);
          if (idx >= 0) oc.thread.messages.splice(idx, 1);
          showToast("Duplicate AI response removed");
          handlingEvent = false;
          return;
        }

        state.recentAiHashes.push(hash);
        if (state.recentAiHashes.length > 8) state.recentAiHashes.shift();
      }

      oc.character.reminderMessage = buildReminder();
    } catch (_) {
      oc.character.reminderMessage = buildReminder();
    }

    handlingEvent = false;
  });

  if (!state.level && oc.character.customData.PUBLIC.mentorDefaults.defaultLevel) {
    const fallbackLevel = String(oc.character.customData.PUBLIC.mentorDefaults.defaultLevel).toLowerCase();
    if (LEVELS.includes(fallbackLevel)) {
      state.level = fallbackLevel;
      state.activeMode = "mentor";
    }
  }

  refreshLiveShortcuts();
  oc.character.reminderMessage = buildReminder();
  panel.style.display = state.panelVisible ? "flex" : "none";
  document.body.appendChild(panel);

  renderPanel();
  if (oc.window && typeof oc.window.show === "function") {
    oc.window.show();
  }
  showToast(state.level ? "Mentor ready" : "Choose a level to begin");
})();
